INSERT INTO words (word, phonetic, pos, level, def_en, ex_en, synonyms) VALUES
('Lug', '/lʌɡ/', 'verb', 'C1', '(sometimes figurative) To haul or drag along (especially something heavy); to carry; to pull.', 'Why do you always lug around so many books?', ARRAY[]::TEXT[]),
