('Lumen', '/ˈluːmən/', 'noun', 'C1', 'In the International System of Units, the derived unit of luminous flux; the light that is emitted in a solid angle of one steradian from a source of one candela. Symbol: lm.', '', ARRAY[]::TEXT[]),
('Luminary', '/ˈluːmɪn(ə)ɹi/', 'noun', 'C1', 'One who is an inspiration to others; one who has achieved success in their chosen field; a leading light.', '', ARRAY['guiding light']::TEXT[]),
